SELECT id, entity_type AS entityType, entity_id AS entityId,
       change_set::text AS changeSet, snapshot_ids AS snapshotIds,
       operator_id AS operatorId, operator_name AS operatorName,
       risk, reason, status,
       created_at AS createdAt, committed_at AS committedAt,
       rolled_back_at AS rolledBackAt, rollback_record_id AS rollbackRecordId,
       error_message AS errorMessage
FROM admin_change_records

    AND operator_id = #{operatorId}
    AND entity_type = #{entityType}
    AND status = #{status}

ORDER BY created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM admin_change_records

    AND operator_id = #{operatorId}
    AND entity_type = #{entityType}
    AND status = #{status}

mapper.update:
UPDATE admin_change_records
SET status = #{status},
    committed_at = CASE WHEN #{status} = 'committed' THEN NOW() ELSE committed_at END,
    rolled_back_at = CASE WHEN #{status} = 'rolled_back' THEN NOW() ELSE rolled_back_at END,
    error_message = #{errorMessage}
WHERE id = #{id}

UPDATE admin_change_records
SET rollback_record_id = #{rollbackRecordId}
WHERE id = #{id}
